    if (tws_api_get_role() == TWS_ROLE_MASTER) {
        if (ble_icon_contrl.miss_flag) {
            ble_icon_contrl.miss_flag = 0;
            puts("ble_icon_contrl.miss_flag...\n");
        } else {
